package sandbox

import (
	"fmt"
	"os"
	"os/exec"
	"syscall"
)

// ExecBwrap replaces the current process with bwrap [args].
//
// In tmux teammate mode (the primary use case), the process runs as the
// foreground process group in a tmux pane, so no setsid is needed. Using
// setsid would detach the controlling terminal, causing Claude to see
// !process.stdout.isTTY and enter non-interactive mode, which breaks
// teammate spawning.
//
// This function does not return on success.
func ExecBwrap(bwrapArgs []string) error {
	bwrapPath, err := exec.LookPath("bwrap")
	if err != nil {
		return fmt.Errorf("bwrap not found: %w", err)
	}

	argv := buildBwrapArgv(bwrapPath, bwrapArgs)
	return syscall.Exec(bwrapPath, argv, os.Environ())
}

// ExecSetsidBwrap replaces the current process with setsid bwrap [args].
// setsid creates a new session, preventing SIGTTOU when bwrap's process
// group is not the foreground group. However, this detaches the controlling
// terminal, making Claude non-interactive. Use ExecBwrap instead when
// the process will be the foreground process (e.g., in a tmux pane).
//
// This function does not return on success.
func ExecSetsidBwrap(bwrapArgs []string) error {
	setsidPath, err := exec.LookPath("setsid")
	if err != nil {
		return fmt.Errorf("setsid not found: %w", err)
	}

	bwrapPath, err := exec.LookPath("bwrap")
	if err != nil {
		return fmt.Errorf("bwrap not found: %w", err)
	}

	argv := buildSetsidArgv(setsidPath, bwrapPath, bwrapArgs)
	return syscall.Exec(setsidPath, argv, os.Environ())
}

// buildBwrapArgv constructs the argv slice for syscall.Exec:
// argv[0] = "bwrap", argv[1:] = bwrapArgs.
func buildBwrapArgv(bwrapPath string, bwrapArgs []string) []string {
	argv := make([]string, 0, 1+len(bwrapArgs))
	argv = append(argv, "bwrap")
	argv = append(argv, bwrapArgs...)
	return argv
}

// buildSetsidArgv constructs the argv slice for syscall.Exec:
// argv[0] = "setsid", argv[1] = bwrapPath, argv[2:] = bwrapArgs.
func buildSetsidArgv(setsidPath, bwrapPath string, bwrapArgs []string) []string {
	argv := make([]string, 0, 2+len(bwrapArgs))
	argv = append(argv, "setsid", bwrapPath)
	argv = append(argv, bwrapArgs...)
	return argv
}

package sandbox

import (
	"fmt"
	"path"
	"path/filepath"
)

// SandboxConfig defines the mount points and environment for a bwrap sandbox.
type SandboxConfig struct {
	AgentRepo    string   // bind rw — agent's git clone
	TeamMailbox  string   // bind rw — ~/.claude/teams/<team>/
	ClaudeHome   string   // bind rw — writable copy of ~/.claude/
	ClaudeBinDir string   // ro-bind — claude binary directory
	ClaudeJSON   string   // ro-bind — ~/.claude.json (API credentials), optional
	AgentSSHDir  string   // ro-bind — agent's deploy key as ~/.ssh/, optional
	ExtraRO      []string // ro-bind — user-configured extra read-only mounts
	ExtraRW      []string // bind    — user-configured extra read-write mounts
	Home         string   // $HOME value inside sandbox
	User         string   // $USER value inside sandbox
	WorkDir      string   // --chdir target (agent repo)
}

// Validate checks that required fields are non-empty and absolute paths.
func (c *SandboxConfig) Validate() error {
	checks := map[string]string{
		"Home":         c.Home,
		"AgentRepo":    c.AgentRepo,
		"ClaudeHome":   c.ClaudeHome,
		"ClaudeBinDir": c.ClaudeBinDir,
		"TeamMailbox":  c.TeamMailbox,
		"WorkDir":      c.WorkDir,
	}
	for name, val := range checks {
		if val == "" {
			return fmt.Errorf("SandboxConfig.%s must not be empty", name)
		}
		if !filepath.IsAbs(val) {
			return fmt.Errorf("SandboxConfig.%s must be an absolute path, got %q", name, val)
		}
	}
	return nil
}

// Args returns the full bwrap argument list.
// Order matters: later mounts overlay earlier ones.
func (c *SandboxConfig) Args() []string {
	args := []string{
		// Base: read-only root, then tmpfs overlays for isolation.
		// Order matters: later mounts overlay earlier ones, so tmpfs
		// must come before any bind mounts under those paths.
		"--ro-bind", "/", "/",
		"--tmpfs", c.Home,
		"--tmpfs", "/tmp",
		"--proc", "/proc",
		"--dev", "/dev",
		// Writable bind mounts (after tmpfs so they overlay correctly)
		"--bind", c.ClaudeHome, path.Join(c.Home, ".claude"),
		"--bind", c.AgentRepo, c.AgentRepo,
		"--bind", c.TeamMailbox, c.TeamMailbox,
		"--ro-bind", c.ClaudeBinDir, c.ClaudeBinDir,
		"--setenv", "HOME", c.Home,
		"--setenv", "USER", c.User,
		"--setenv", "SSH_AUTH_SOCK", "",
	}

	if c.ClaudeJSON != "" {
		args = append(args, "--ro-bind", c.ClaudeJSON, path.Join(c.Home, ".claude.json"))
	}

	if c.AgentSSHDir != "" {
		args = append(args, "--ro-bind", c.AgentSSHDir, path.Join(c.Home, ".ssh"))
	}

	for _, p := range c.ExtraRO {
		args = append(args, "--ro-bind", p, p)
	}
	for _, p := range c.ExtraRW {
		args = append(args, "--bind", p, p)
	}

	args = append(args, "--chdir", c.WorkDir)

	return args
}

// 7. Inject agent profile flags (model, effort) if configured
finalArgs := injectProfileFlags(parsed.AgentName, parsed.AllArgs, ws.Config.AgentProfiles)

// 8. Build full command and exec.
// Two strategies depending on SEA_USE_SETSID env var:
//   "1" (or unset): setsid + --print "start" — non-interactive mode (current default)
//   "0": direct bwrap — teammate keeps TTY, runs in interactive mode
//
// The setsid approach prevents SIGTTOU but forces non-interactive mode.
// Direct bwrap should work when the process is the foreground group in a
// tmux pane, preserving interactive mode. Use SEA_USE_SETSID=0 to test.
bwrapArgs := cfg.Args()
bwrapArgs = append(bwrapArgs, "--", claudeBin)

useSetsid := os.Getenv("SEA_USE_SETSID") != "0"
fmt.Fprintf(os.Stderr, "[wrapper] SEA_USE_SETSID=%q useSetsid=%v\n", os.Getenv("SEA_USE_SETSID"), useSetsid)
fmt.Fprintf(os.Stderr, "[wrapper] finalArgs=%v\n", finalArgs)

if useSetsid {
	// Inject --print "start" since setsid detaches the terminal,
	// making Claude enter non-interactive mode which requires --print.
	// The teammate's actual instructions come via the mailbox.
	finalArgs = append(finalArgs, "--print", "start")
	bwrapArgs = append(bwrapArgs, finalArgs...)
	return sandbox.ExecSetsidBwrap(bwrapArgs)
}

// Direct bwrap — no setsid, no --print. Teammate runs interactive.
bwrapArgs = append(bwrapArgs, finalArgs...)
fmt.Fprintf(os.Stderr, "[wrapper] exec: bwrap %v\n", bwrapArgs)

