	if out, err := exec.Command("git", "clone", "--bare", tmpDir, canonicalPath).CombinedOutput(); err != nil {
		return fmt.Errorf("git clone --bare: %s: %w", out, err)
	}

	wsCfg := workspace.Config{
		RepoURL:       tmpDir,
		ProjectPath:   tmpDir,
		DefaultBranch: "main",
	}
	yamlData, _ := yaml.Marshal(&wsCfg)
	os.WriteFile(filepath.Join(wsDir, "workspace.yaml"), yamlData, 0644)

	// Wrapper script that selects exec mode via env var
	wrapperBin := filepath.Join(tmpDir, "teammate-wrapper")
	logFile := filepath.Join(tmpDir, "wrapper.log")
	wrapperContent := fmt.Sprintf("#!/bin/sh\necho \"[wrapper] invoked at $(date)\" >> %q\necho \"[wrapper] args: $@\" >> %q\necho \"[wrapper] SEA_DIAG_SETSID=$SEA_DIAG_SETSID\" >> %q\nexec %q teammate-wrapper \"$@\"\n",
		logFile, logFile, logFile, seaBin)
	os.WriteFile(wrapperBin, []byte(wrapperContent), 0755)

	// Build the teammate-wrapper invocation.
	// We call it directly (not through CLAUDE_CODE_TEAMMATE_COMMAND) to test
	// the wrapper → bwrap → claude pipeline in isolation.
	agentName := "diag-agent"
	teamName := "diag-team"

	// The teammate-wrapper needs to find the workspace, so we cd to tmpDir.
	// We pass the minimal flags that teammate-wrapper requires.
	var launcherLines []string
	launcherLines = append(launcherLines, "#!/bin/sh")
	launcherLines = append(launcherLines, fmt.Sprintf("cd %q", tmpDir))

	// Set env var to control setsid behavior in teammate-wrapper
	if useSetsid {
		launcherLines = append(launcherLines, "export SEA_USE_SETSID=1")
	} else {
		launcherLines = append(launcherLines, "export SEA_USE_SETSID=0")
	}

	// Unset env vars that block nested Claude sessions
	launcherLines = append(launcherLines, "unset CLAUDECODE")
	launcherLines = append(launcherLines, "unset CLAUDE_CODE_ENTRYPOINT")
	launcherLines = append(launcherLines, "unset CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS")

	// Run teammate-wrapper directly with minimal flags.
	// --print asks Claude to write a results file (tests stdout + API).
	// Without --print (when !useSetsid), Claude should enter interactive mode.
	args := fmt.Sprintf("--agent-name %s --team-name %s --agent-id %s@%s",
		agentName, teamName, agentName, teamName)

	// Both modes go through the same teammate-wrapper.
	// SEA_USE_SETSID controls whether it uses setsid or direct bwrap.
	launcherLines = append(launcherLines,
		fmt.Sprintf("exec %q teammate-wrapper %s", seaBin, args))

	launcherPath := filepath.Join(tmpDir, "launch.sh")
	os.WriteFile(launcherPath, []byte(strings.Join(launcherLines, "\n")+"\n"), 0755)

	return nil
}

