func runDiag(timeout time.Duration) error {
	claudeBin, err := detect.FindClaudeBinary()
	if err != nil {
		return fmt.Errorf("finding claude binary: %w", err)
	}

	seaBin, err := os.Executable()
	if err != nil {
		return fmt.Errorf("resolving sea binary: %w", err)
	}

	if _, err := exec.LookPath("bwrap"); err != nil {
		return fmt.Errorf("bwrap not found: install with sudo apt install bubblewrap")
	}

	if _, err := exec.LookPath("tmux"); err != nil {
		return fmt.Errorf("tmux not found")
	}

	// Create temp workspace
	tmpDir, err := os.MkdirTemp("", "sea-diag-*")
	if err != nil {
		return fmt.Errorf("creating temp dir: %w", err)
	}

	fmt.Printf("=== sea diag ===\n")
	fmt.Printf("  claude:  %s\n", claudeBin)
	fmt.Printf("  sea:     %s\n", seaBin)
	fmt.Printf("  tmpdir:  %s\n", tmpDir)
	fmt.Printf("  timeout: %s\n", timeout)
	fmt.Println()

	// Set up minimal workspace
	if err := diagSetup(tmpDir, seaBin); err != nil {
		os.RemoveAll(tmpDir)
		return fmt.Errorf("setup: %w", err)
	}

	// Run teammate-wrapper in a tmux pane
	sessionName := fmt.Sprintf("sea-diag-%d", os.Getpid())
	launcherPath := filepath.Join(tmpDir, "launch.sh")

	tmuxCmd := exec.Command("tmux", "new-session", "-d", "-s", sessionName,
		"-x", "200", "-y", "50",
		launcherPath,
	)
	if out, err := tmuxCmd.CombinedOutput(); err != nil {
		return fmt.Errorf("creating tmux session: %s: %w", out, err)
	}
	defer exec.Command("tmux", "kill-session", "-t", sessionName).Run()

	fmt.Printf("Running in tmux session %q\n\n", sessionName)

	// Poll for Claude process inside bwrap
	timer := time.NewTimer(timeout)
	defer timer.Stop()
	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	claudeRunning := false

	for !claudeRunning {
		select {
		case <-ticker.C:
			alive := exec.Command("tmux", "has-session", "-t", sessionName).Run() == nil
			if !alive {
				break
			}

			// Get pane PID
			panePID, err := exec.Command("tmux", "display-message", "-t", sessionName, "-p", "#{pane_pid}").Output()
			if err != nil {
				continue
			}
			pid := strings.TrimSpace(string(panePID))

			// Check process tree: look for bwrap and claude processes
			psOut, err := exec.Command("ps", "--forest", "-o", "pid,stat,args", "-g", pid).Output()
			if err != nil {
				continue
			}

			lines := string(psOut)
			hasBwrap := strings.Contains(lines, "bwrap")
			hasClaude := strings.Contains(lines, claudeBin)
			// "+" in STAT means foreground process group
			isForeground := false
			for _, line := range strings.Split(lines, "\n") {
				if strings.Contains(line, claudeBin) {
					fields := strings.Fields(line)
					if len(fields) >= 2 && strings.Contains(fields[1], "+") {
						isForeground = true
					}
				}
			}

			fmt.Printf("  bwrap=%v claude=%v foreground=%v\n", hasBwrap, hasClaude, isForeground)

			if hasBwrap && hasClaude && isForeground {
				claudeRunning = true
			}

			if !alive {
				fmt.Println("\nTmux session died.")
				goto done
			}

		case <-timer.C:
			fmt.Fprintf(os.Stderr, "\nTimeout after %s\n", timeout)
			goto done
		}
	}

done:
	fmt.Println()
	if claudeRunning {
		fmt.Println("PASS: Claude is running in interactive mode inside bwrap sandbox.")
		fmt.Println("  - bwrap process present")
		fmt.Println("  - Claude binary running as child")
		fmt.Println("  - Process is in foreground group (no SIGTTOU)")
	} else {
		fmt.Println("FAIL: Claude did not start correctly inside bwrap.")

		// Try to capture any error output
		if out, err := exec.Command("tmux", "capture-pane", "-t", sessionName, "-p").Output(); err == nil {
			stripped := stripANSI(string(out))
			trimmed := strings.TrimSpace(stripped)
			if trimmed != "" {
				fmt.Printf("\nPane output:\n%s\n", trimmed)
			}
			if strings.Contains(stripped, "Input must be provided") {
				fmt.Println("\nDIAGNOSIS: Claude entered non-interactive mode (no TTY).")
			} else if strings.Contains(stripped, "cannot launch inside another") {
				fmt.Println("\nDIAGNOSIS: CLAUDECODE env var not unset.")
			} else if trimmed == "" {
				fmt.Println("\nDIAGNOSIS: No output — possible SIGTTOU or crash.")
			}
		}
	}

	exec.Command("tmux", "kill-session", "-t", sessionName).Run()
	fmt.Printf("\nInspect: %s\n", tmpDir)
	return nil
}

