# Check if the acceptance is stored in claude.json
python3 -c "
import json
d=json.load(open('/home/ketan/.claude.json'))
# Check for bypass_permissions keys at top level and in projects
for k,v in d.items():
    if 'bypass' in str(k).lower() or 'permissions' in str(k).lower():
        print(f'top: {k}={v}')
# Check projects
for proj_path, proj_cfg in d.get('projects',{}).items():
    for k,v in proj_cfg.items():
        if 'bypass' in str(k).lower() or 'permissions' in str(k).lower() or 'dangerous' in str(k).lower():
            print(f'{proj_path}: {k}={v}')
" 2>/dev/null
echo "==="
# Check for any bypass-related keys
python3 -c "
import json
d=json.load(open('/home/ketan/.claude.json'))
for k in sorted(d.keys()):
    if k != 'projects':
        print(f'{k}: {type(d[k]).__name__}')
" 2>/dev/null

# Check project-level keys for the agentsea project
python3 -c "
import json
d=json.load(open('/home/ketan/.claude.json'))
for proj_path, proj_cfg in d.get('projects',{}).items():
    if isinstance(proj_cfg, dict):
        for k in proj_cfg:
            if 'bypass' in k.lower() or 'accept' in k.lower() or 'skip' in k.lower():
                print(f'{proj_path}: {k}={proj_cfg[k]}')
# Also just show all keys for one project
for proj_path, proj_cfg in d.get('projects',{}).items():
    if isinstance(proj_cfg, dict) and 'agentsea' in proj_path:
        for k in sorted(proj_cfg.keys()):
            print(f'  {k}: {proj_cfg[k]}')
        break
" 2>/dev/null

