finalArgs := injectProfileFlags(parsed.AgentName, parsed.AllArgs, ws.Config.AgentProfiles)

// 8. Clear env vars that prevent nested Claude sessions.
// Claude Code sets CLAUDECODE=1 when invoking CLAUDE_CODE_TEAMMATE_COMMAND.
// The teammate is a fresh Claude instance and must not see these.
