// prepareClaudeHome creates a writable copy of ~/.claude/ with symlinks dereferenced.
// Returns the path to the copy.
func prepareClaudeHome(ws *workspace.Workspace, agentName, teamName string) (string, error) {
	target := filepath.Join(ws.Dir, "agents", agentName, "claude-home")

	if _, err := os.Stat(target); os.IsNotExist(err) {
		src := filepath.Join(os.Getenv("HOME"), ".claude")

		// cp -aL dereferences symlinks (settings.json, CLAUDE.md may be symlinks to dotfiles)
		// Fall back to cp -a if -aL fails, then to mkdir as last resort.
		if out, err := exec.Command("cp", "-aL", src, target).CombinedOutput(); err != nil {
			if out2, err2 := exec.Command("cp", "-a", src, target).CombinedOutput(); err2 != nil {
				if err3 := os.MkdirAll(target, 0755); err3 != nil {
					return "", fmt.Errorf("cp -aL: %s, cp -a: %s, mkdir: %w", out, out2, err3)
				}
			}
		}
	}

	// Ensure teams/<teamName> subdir exists inside the copy for mailbox config
	teamsDir := filepath.Join(target, "teams", teamName)
	if err := os.MkdirAll(teamsDir, 0755); err != nil {
		return "", fmt.Errorf("creating teams dir in claude home: %w", err)
