					return "", fmt.Errorf("cp -aL: %s, cp -a: %s, mkdir: %w", out, out2, err3)
				}
			}
		}
	}

	// Ensure teams/<teamName> subdir exists inside the copy for mailbox config
	teamsDir := filepath.Join(target, "teams", teamName)
	if err := os.MkdirAll(teamsDir, 0755); err != nil {
		return "", fmt.Errorf("creating teams dir in claude home: %w", err)
	}

	// Pre-create the project directory for the agent repo so Claude
	// recognizes it as a trusted workspace and skips the trust dialog.
	// Claude encodes paths by replacing "/" with "-" and stripping the leading "/".
	agentRepo := ws.AgentRepoPath(agentName)
	encodedPath := strings.ReplaceAll(agentRepo, "/", "-")
	projectDir := filepath.Join(target, "projects", encodedPath)
	if err := os.MkdirAll(projectDir, 0755); err != nil {
		return "", fmt.Errorf("creating project dir in claude home: %w", err)
	}

	return target, nil
}

// preTrustAgentRepo creates a modified copy of ~/.claude.json with
// hasTrustDialogAccepted set for the agent repo path. Returns the
// path to the modified copy (stored alongside the agent's claude-home).
func preTrustAgentRepo(origPath string, ws *workspace.Workspace, agentName, agentRepo string) (string, error) {
	target := filepath.Join(ws.Dir, "agents", agentName, "claude.json")

	data, err := os.ReadFile(origPath)
	if err != nil {
		return "", fmt.Errorf("reading %s: %w", origPath, err)
	}

	var config map[string]interface{}
	if err := json.Unmarshal(data, &config); err != nil {
		return "", fmt.Errorf("parsing %s: %w", origPath, err)
	}

	// Claude Code stores trust per project path: projects["/path/to/repo"].hasTrustDialogAccepted
	projects, _ := config["projects"].(map[string]interface{})
	if projects == nil {
		projects = make(map[string]interface{})
		config["projects"] = projects
	}

	projConfig, _ := projects[agentRepo].(map[string]interface{})
	if projConfig == nil {
		projConfig = make(map[string]interface{})
	}
	projConfig["hasTrustDialogAccepted"] = true
	projConfig["bypassPermissionsModeAccepted"] = true
	projConfig["hasCompletedProjectOnboarding"] = true
	projects[agentRepo] = projConfig

	// Ensure global onboarding is also marked complete
	config["hasCompletedOnboarding"] = true

	out, err := json.MarshalIndent(config, "", "  ")
	if err != nil {
		return "", fmt.Errorf("marshaling config: %w", err)
	}

	if err := os.WriteFile(target, append(out, '\n'), 0644); err != nil {
		return "", fmt.Errorf("writing %s: %w", target, err)
	}

	return target, nil
}

